} from "@procertus-ui/ui";

import { cn } from "../lib/utils";

export type PrototypeCardProps = {
  children: React.ReactNode;
  /** Optional heading inside the prototype chrome. */
  title?: React.ReactNode;
  /** Optional supporting copy below the title (muted body style). */
  description?: React.ReactNode;
  /** Optional fine print below the description (smaller, muted — e.g. prototype hints). */
  notice?: React.ReactNode;
  /** When false, hides the corner “Demo” badge. @default true */
  showDemoBadge?: boolean;
  /** Label text for the demo badge. @default "Demo" */
  demoBadgeLabel?: React.ReactNode;
  /** Accessible longer description for the badge (`title` attribute). */
  demoBadgeTitle?: string;
  className?: string;
  /** Applied to the inner content region that wraps optional header + `children`. */
  cardContentClassName?: string;
};

/**
 * Framed region for prototype-only UI: dotted border, muted wash, optional “Demo” badge,
 * and optional title / description / notice blocks above variable `children`.
 */
export function PrototypeCard({
  children,
  title,
  description,
  notice,
  showDemoBadge = true,
  demoBadgeLabel = "Demo",
  demoBadgeTitle = "Alleen in deze prototype-build: kies een demo-gebruiker.",
  className,
  cardContentClassName,
}: PrototypeCardProps) {
  const hasHeader = Boolean(title ?? description ?? notice);

  return (
    <Card
      className={cn(
        "relative gap-0 border-2 border-dotted border-muted-foreground/45 bg-muted/20 py-0 shadow-none ring-0",
        className,
      )}
    >
      {showDemoBadge ? (
        <Badge
          variant="outline"
          title={demoBadgeTitle}
          className="absolute top-3 right-3 z-10 border-transparent bg-prototype text-prototype-foreground hover:bg-prototype"
        >
          {demoBadgeLabel}
        </Badge>
      ) : null}

      {hasHeader ? (
        <CardHeader className="gap-1 px-section pb-0 pt-section text-center">
          {title ? <CardTitle className="text-base">{title}</CardTitle> : null}
          {description ? (
            <CardDescription className="leading-6">{description}</CardDescription>
          ) : null}
          {notice ? (
            <div className="mt-2 text-xs leading-relaxed text-muted-foreground">{notice}</div>
          ) : null}
        </CardHeader>
      ) : null}

      <CardContent
        className={cn(
          "space-y-4 px-section py-section",
          hasHeader && "pt-4",
          cardContentClassName,
        )}
      >
        {children}
      </CardContent>
    </Card>
  );
}

import * as React from "react";

import { Field, FieldDescription, FieldLabel } from "@procertus-ui/ui";
import { LoginForm } from "@procertus-ui/ui-lib";

import { cn } from "../lib/utils";

import { useMockPrototypeAuthContext } from "./mock-prototype-auth-context";
import { MockPrototypeUserSelect } from "./MockPrototypeUserSelect";
import { PrototypeCard } from "./PrototypeCard";

export type MockPrototypePasswordlessLoginFormProps = {
  /** Called after the prototype session is established (`login` succeeded). */
  onLoggedIn?: () => void;
  /** Submit button label (passwordless). */
  submitLabel?: string;
  /** Optional wrapper class for spacing/layout. */
  className?: string;
  /**
   * Message when submit runs without a selected prototype user.
   * @default Dutch copy for the extranet prototype.
   */
  pickerRequiredMessage?: string;
  isSubmitting?: boolean;
};

/**
 * Passwordless-style login form plus the prototype user dropdown.
 * The email field stays in sync with the selected user; sign-in uses the picker selection.
 */
export function MockPrototypePasswordlessLoginForm({
  onLoggedIn,
  submitLabel,
  className,
  pickerRequiredMessage = "Kies een prototypegebruiker om verder te gaan.",
  isSubmitting = false,
}: MockPrototypePasswordlessLoginFormProps) {
  const { login, users, selectedUserId } = useMockPrototypeAuthContext();
  const [email, setEmail] = React.useState("");
  const [error, setError] = React.useState<string | undefined>();

  React.useEffect(() => {
    if (selectedUserId === null) {
      setEmail("");
      return;
    }
    const user = users.find((u) => u.id === selectedUserId);
    setEmail(user?.email ?? "");
  }, [selectedUserId, users]);

  return (
    <div className={cn("flex flex-col gap-section", className)}>
      <PrototypeCard>
        <Field>
          <FieldLabel htmlFor="mock-prototype-user-select">Prototypegebruiker</FieldLabel>
          <FieldDescription>
            Kies een demo-account; het e-mailveld hieronder wordt automatisch ingevuld.
          </FieldDescription>
          <MockPrototypeUserSelect
            id="mock-prototype-user-select"
            className="w-full"
            aria-label="Prototypegebruiker"
          />
        </Field>
      </PrototypeCard>

      <LoginForm
        variant="passwordless"
        submitLabel={submitLabel}
        email={email}
        onEmailChange={(value) => {
          setEmail(value);
          setError(undefined);
        }}
        error={error}
        isSubmitting={isSubmitting}
        onSubmit={() => {
          if (selectedUserId === null) {
            setError(pickerRequiredMessage);
            return;
          }
          setError(undefined);
          login(selectedUserId);
          onLoggedIn?.();
        }}
      />
    </div>
  );
}

